/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP
rates = {'same_city': Decimal('5'), 'same_province': Decimal('8'), 'adjacent': Decimal('12'), 'remote': Decimal('18')}
rows=[]
with open('input.csv', newline='') as f:
    for r in csv.DictReader(f):
        aw=Decimal(r['actual_weight']); l=Decimal(r['length']); w=Decimal(r['width']); h=Decimal(r['height'])
        bill=max(aw, l*w*h/Decimal('6000'))
        rate=rates[r['zone']]
        cost=rate + max(Decimal('0'), bill-Decimal('1')) * rate * Decimal('0.6')
        mult=Decimal('1')
        if r['fragile']=='True': mult += Decimal('0.15')
        if max(l,w,h) > Decimal('100'): mult += Decimal('0.25')
        if r['cold_chain']=='True': mult += Decimal('0.30')
        cost *= mult
        if r['vip']=='True': cost *= Decimal('0.9')
        if cost < Decimal('10'): cost = Decimal('10')
        cost = cost.quantize(Decimal('0.1'), rounding=ROUND_HALF_UP)
        rows.append({'id': r['id'], 'cost': float(cost)})
print(json.dumps(rows, ensure_ascii=False, indent=2))
PY"

